const ALLOWED_RELATION_LABEL_BY_PAIR: Record<string, string> = {
    "activity|person": "part of",
    "requirement|requirement": "details",
    "activity|requirement": "derived from",
    "concept|insight": "part of",
    "concept|concept": "composes",
    "activity|concept": "relevant to",
    "activity|insight": "derived from",
    "activity|object": "generated by",
    "object|object": "relevant to",
    "object|requirement": "tackles",
};

export function relationPairKey(a: string, b: string): string {
    return [a.toLowerCase(), b.toLowerCase()].sort().join("|");
}

export function relationLabelFor(a: string, b: string): string | undefined {
    return ALLOWED_RELATION_LABEL_BY_PAIR[relationPairKey(a, b)];
}

export function isAllowedConnection(a?: string, b?: string): boolean {
    if (!a || !b) return false;
    return !!relationLabelFor(a, b);
}